"use strict";(globalThis.webpackChunkwebsite=globalThis.webpackChunkwebsite||[]).push([[8687],{5742(e,t,n){n.r(t),n.d(t,{assets:()=>c,contentTitle:()=>a,default:()=>d,frontMatter:()=>o,metadata:()=>i,toc:()=>p});const i=JSON.parse('{"id":"tier-3-advanced/reflection/patterns","title":"Patterns: Reflection & Self-critique","description":"Practical patterns for generate-critique-revise loops, constitutional critique, and stop-when-satisfied reflection.","source":"@site/docs/tier-3-advanced/26-reflection/patterns.mdx","sourceDirName":"tier-3-advanced/26-reflection","slug":"/tier-3-advanced/reflection/patterns","permalink":"/ai-native-course/tier-3-advanced/reflection/patterns","draft":false,"unlisted":false,"tags":[],"version":"current","lastUpdatedAt":1774637831000,"sidebarPosition":3,"frontMatter":{"title":"Patterns: Reflection & Self-critique","sidebar_position":3,"description":"Practical patterns for generate-critique-revise loops, constitutional critique, and stop-when-satisfied reflection."},"sidebar":"courseSidebar","previous":{"title":"Concepts: Reflection & Self-critique","permalink":"/ai-native-course/tier-3-advanced/reflection/concepts"},"next":{"title":"Lab: Self-improving Summarizer","permalink":"/ai-native-course/tier-3-advanced/reflection/lab"}}');var r=n(74848),s=n(28453);const o={title:"Patterns: Reflection & Self-critique",sidebar_position:3,description:"Practical patterns for generate-critique-revise loops, constitutional critique, and stop-when-satisfied reflection."},a="Patterns: Reflection & Self-critique",c={},p=[{value:"Pattern 1: Simple G-C-R Loop (2 Iterations)",id:"pattern-1-simple-g-c-r-loop-2-iterations",level:2},{value:"Pattern 2: Constitutional Critique Against a Principle List",id:"pattern-2-constitutional-critique-against-a-principle-list",level:2},{value:"Pattern 3: Stop-When-Satisfied \u2014 Continue Until Critique Approves",id:"pattern-3-stop-when-satisfied--continue-until-critique-approves",level:2},{value:"Anti-Patterns",id:"anti-patterns",level:2}];function l(e){const t={code:"code",h1:"h1",h2:"h2",header:"header",hr:"hr",p:"p",pre:"pre",strong:"strong",...(0,s.R)(),...e.components};return(0,r.jsxs)(r.Fragment,{children:[(0,r.jsx)(t.header,{children:(0,r.jsx)(t.h1,{id:"patterns-reflection--self-critique",children:"Patterns: Reflection & Self-critique"})}),"\n",(0,r.jsx)(t.h2,{id:"pattern-1-simple-g-c-r-loop-2-iterations",children:"Pattern 1: Simple G-C-R Loop (2 Iterations)"}),"\n",(0,r.jsx)(t.p,{children:"Generate a draft, critique it, revise once. This captures most of the quality gain with a fixed, predictable cost (3 LLM calls total)."}),"\n",(0,r.jsx)(t.pre,{children:(0,r.jsx)(t.code,{className:"language-python",children:'from anthropic import Anthropic\n\nclient = Anthropic()\nMODEL = "claude-3-haiku-20240307"\n\n\ndef generate(prompt: str) -> str:\n    """Generate an initial response."""\n    response = client.messages.create(\n        model=MODEL,\n        max_tokens=1024,\n        messages=[{"role": "user", "content": prompt}],\n    )\n    return response.content[0].text\n\n\ndef critique(original_prompt: str, draft: str) -> str:\n    """Identify specific flaws in the draft."""\n    critique_prompt = (\n        f"Original request: {original_prompt}\\n\\n"\n        f"Draft response:\\n{draft}\\n\\n"\n        "Critique this response. List specific flaws: inaccuracies, missing points, "\n        "verbosity, unclear phrasing, or any other weaknesses. Be specific and direct."\n    )\n    response = client.messages.create(\n        model=MODEL,\n        max_tokens=512,\n        messages=[{"role": "user", "content": critique_prompt}],\n    )\n    return response.content[0].text\n\n\ndef revise(original_prompt: str, draft: str, critique_text: str) -> str:\n    """Revise the draft to address the critique."""\n    revise_prompt = (\n        f"Original request: {original_prompt}\\n\\n"\n        f"Draft response:\\n{draft}\\n\\n"\n        f"Critique:\\n{critique_text}\\n\\n"\n        "Write an improved version that addresses all the identified issues. "\n        "Output only the revised response, no meta-commentary."\n    )\n    response = client.messages.create(\n        model=MODEL,\n        max_tokens=1024,\n        messages=[{"role": "user", "content": revise_prompt}],\n    )\n    return response.content[0].text\n\n\ndef gcr_loop(prompt: str, iterations: int = 2) -> str:\n    """Generate-Critique-Revise for a fixed number of iterations."""\n    draft = generate(prompt)\n    for i in range(iterations):\n        critique_text = critique(prompt, draft)\n        draft = revise(prompt, draft, critique_text)\n    return draft\n\n\n# Usage\nresult = gcr_loop(\n    "Summarise the key differences between supervised and unsupervised learning.",\n    iterations=2,\n)\nprint(result)\n'})}),"\n",(0,r.jsxs)(t.p,{children:[(0,r.jsx)(t.strong,{children:"When to use:"})," any task where output quality matters and you can tolerate 3x the normal LLM cost. Two iterations is the sweet spot for most use cases."]}),"\n",(0,r.jsx)(t.hr,{}),"\n",(0,r.jsx)(t.h2,{id:"pattern-2-constitutional-critique-against-a-principle-list",children:"Pattern 2: Constitutional Critique Against a Principle List"}),"\n",(0,r.jsx)(t.p,{children:"Evaluate the output against named principles. The critique returns a structured verdict for each principle, making quality assessment auditable and targetable."}),"\n",(0,r.jsx)(t.pre,{children:(0,r.jsx)(t.code,{className:"language-python",children:'from anthropic import Anthropic\n\nclient = Anthropic()\nMODEL = "claude-3-haiku-20240307"\n\nPRINCIPLES = [\n    "Accurate: does not state anything false or unverified",\n    "Helpful: directly addresses the user\'s actual question",\n    "Concise: no unnecessary padding or repetition",\n    "Safe: does not contain harmful, misleading, or inappropriate content",\n]\n\n\ndef constitutional_critique(prompt: str, draft: str, principles: list[str]) -> str:\n    """Evaluate the draft against each principle and identify violations."""\n    principles_block = "\\n".join(f"{i+1}. {p}" for i, p in enumerate(principles))\n    critique_prompt = (\n        f"User request: {prompt}\\n\\n"\n        f"Response to evaluate:\\n{draft}\\n\\n"\n        f"Evaluate this response against each of these principles:\\n{principles_block}\\n\\n"\n        "For each principle, state: PASS or FAIL, and if FAIL explain why in one sentence."\n    )\n    response = client.messages.create(\n        model=MODEL,\n        max_tokens=512,\n        messages=[{"role": "user", "content": critique_prompt}],\n    )\n    return response.content[0].text\n\n\ndef constitutional_revise(prompt: str, draft: str, violations: str) -> str:\n    """Revise the draft to fix constitutional violations."""\n    revise_prompt = (\n        f"User request: {prompt}\\n\\n"\n        f"Draft:\\n{draft}\\n\\n"\n        f"Violations found:\\n{violations}\\n\\n"\n        "Rewrite the response to fix all violations. Output only the revised response."\n    )\n    response = client.messages.create(\n        model=MODEL,\n        max_tokens=1024,\n        messages=[{"role": "user", "content": revise_prompt}],\n    )\n    return response.content[0].text\n\n\n# Usage\nprompt = "Explain how vaccines work."\ndraft_response = client.messages.create(\n    model=MODEL,\n    max_tokens=512,\n    messages=[{"role": "user", "content": prompt}],\n).content[0].text\n\nviolations = constitutional_critique(prompt, draft_response, PRINCIPLES)\nprint("Violations:\\n", violations)\n\nif "FAIL" in violations:\n    improved = constitutional_revise(prompt, draft_response, violations)\n    print("\\nImproved:\\n", improved)\n'})}),"\n",(0,r.jsxs)(t.p,{children:[(0,r.jsx)(t.strong,{children:"When to use:"})," production systems where specific quality requirements must be met and violations need to be logged. The explicit principle list is auditable \u2014 you can trace exactly why a revision was triggered."]}),"\n",(0,r.jsx)(t.hr,{}),"\n",(0,r.jsx)(t.h2,{id:"pattern-3-stop-when-satisfied--continue-until-critique-approves",children:"Pattern 3: Stop-When-Satisfied \u2014 Continue Until Critique Approves"}),"\n",(0,r.jsx)(t.p,{children:"Keep revising until the critique says there are no major issues, or until a maximum iteration count is reached. Dynamically terminates when quality is sufficient."}),"\n",(0,r.jsx)(t.pre,{children:(0,r.jsx)(t.code,{className:"language-python",children:'from anthropic import Anthropic\n\nclient = Anthropic()\nMODEL = "claude-3-haiku-20240307"\nMAX_ITERATIONS = 3\n\n\ndef generate_initial(prompt: str) -> str:\n    response = client.messages.create(\n        model=MODEL,\n        max_tokens=1024,\n        messages=[{"role": "user", "content": prompt}],\n    )\n    return response.content[0].text\n\n\ndef critique_with_verdict(prompt: str, draft: str) -> tuple[str, bool]:\n    """\n    Returns (critique_text, satisfied).\n    satisfied=True means no major issues \u2014 stop iterating.\n    """\n    critique_prompt = (\n        f"Request: {prompt}\\n\\nDraft:\\n{draft}\\n\\n"\n        "List any significant issues with this response. "\n        "If there are no major issues, end your response with the exact phrase: NO MAJOR ISSUES"\n    )\n    response = client.messages.create(\n        model=MODEL,\n        max_tokens=512,\n        messages=[{"role": "user", "content": critique_prompt}],\n    )\n    critique_text = response.content[0].text\n    satisfied = "NO MAJOR ISSUES" in critique_text.upper()\n    return critique_text, satisfied\n\n\ndef revise_draft(prompt: str, draft: str, critique_text: str) -> str:\n    revise_prompt = (\n        f"Request: {prompt}\\n\\nDraft:\\n{draft}\\n\\nIssues:\\n{critique_text}\\n\\n"\n        "Write an improved version addressing all issues. Output only the revised response."\n    )\n    response = client.messages.create(\n        model=MODEL,\n        max_tokens=1024,\n        messages=[{"role": "user", "content": revise_prompt}],\n    )\n    return response.content[0].text\n\n\ndef reflect_until_satisfied(prompt: str) -> str:\n    """Iterate until satisfied or MAX_ITERATIONS reached."""\n    draft = generate_initial(prompt)\n\n    for iteration in range(MAX_ITERATIONS):\n        critique_text, satisfied = critique_with_verdict(prompt, draft)\n        if satisfied:\n            print(f"Satisfied after {iteration} revisions.")\n            break\n        draft = revise_draft(prompt, draft, critique_text)\n    else:\n        print(f"Reached max iterations ({MAX_ITERATIONS}).")\n\n    return draft\n\n\n# Usage\nfinal = reflect_until_satisfied(\n    "Write a 2-sentence explanation of transformer attention for a junior engineer."\n)\nprint(final)\n'})}),"\n",(0,r.jsxs)(t.p,{children:[(0,r.jsx)(t.strong,{children:"When to use:"})," when quality thresholds vary \u2014 some prompts need zero revisions, others need two. More efficient than a fixed-iteration loop because easy prompts exit early."]}),"\n",(0,r.jsx)(t.hr,{}),"\n",(0,r.jsx)(t.h2,{id:"anti-patterns",children:"Anti-Patterns"}),"\n",(0,r.jsxs)("div",{className:"antipattern",children:[(0,r.jsx)(t.p,{children:(0,r.jsx)(t.strong,{children:"Too many iterations \u2014 diminishing returns"})}),(0,r.jsx)(t.pre,{children:(0,r.jsx)(t.code,{className:"language-python",children:"# Bad \u2014 5 iterations almost never justifies the 10x cost\nresult = gcr_loop(prompt, iterations=5)\n\n# Good \u2014 2 iterations captures most of the quality gain\nresult = gcr_loop(prompt, iterations=2)\n"})}),(0,r.jsx)(t.p,{children:(0,r.jsx)(t.strong,{children:"Critique that is too vague to act on"})}),(0,r.jsx)(t.pre,{children:(0,r.jsx)(t.code,{className:"language-python",children:'# Bad \u2014 the model cannot improve without knowing what is wrong\ncritique_prompt = "Is this response good? Make it better."\n\n# Good \u2014 specific criteria, specific violations\ncritique_prompt = (\n    "Review this response. Identify: (1) factual errors, "\n    "(2) missing key points from the source, "\n    "(3) verbose sentences that should be cut."\n)\n'})})]})]})}function d(e={}){const{wrapper:t}={...(0,s.R)(),...e.components};return t?(0,r.jsx)(t,{...e,children:(0,r.jsx)(l,{...e})}):l(e)}},28453(e,t,n){n.d(t,{R:()=>o,x:()=>a});var i=n(96540);const r={},s=i.createContext(r);function o(e){const t=i.useContext(s);return i.useMemo(function(){return"function"==typeof e?e(t):{...t,...e}},[t,e])}function a(e){let t;return t=e.disableParentContext?"function"==typeof e.components?e.components(r):e.components||r:o(e.components),i.createElement(s.Provider,{value:t},e.children)}}}]);